import{_ as e,o,c as d,au as i}from"./chunks/framework.DjOerXpq.js";const u=JSON.parse('{"title":"Client API","description":"Helper functions to simplify the `upload` and `download` logic for the client side.","frontmatter":{"title":"Client API","description":"Helper functions to simplify the `upload` and `download` logic for the client side."},"headers":[],"relativePath":"packages/feathers-s3/API/client.md","filePath":"packages/feathers-s3/API/client.md"}'),a={name:"packages/feathers-s3/API/client.md"};function n(r,t,c,s,h,l){return o(),d("div",null,[...t[0]||(t[0]=[i('<h1 id="client" tabindex="-1">Client <a class="header-anchor" href="#client" aria-label="Permalink to &quot;Client&quot;">​</a></h1><h2 id="getclientservice-app-options" tabindex="-1">getClientService (app, options) <a class="header-anchor" href="#getclientservice-app-options" aria-label="Permalink to &quot;getClientService (app, options)&quot;">​</a></h2><p>Return the client service interface. The client service exposes the custom methods defined in the <a href="#service">Service</a> and is also decorated with 2 helper functions that really simplify the logic when implementing a client application, notably for multipart upload.</p><table tabindex="0"><thead><tr><th>Argument</th><th>Description</th><th>Required</th></tr></thead><tbody><tr><td><code>app</code></td><td>the <strong>Feathers</strong> client application</td><td>yes</td></tr><tr><td><code>options</code></td><td>the options to pass to the client service</td><td>no</td></tr></tbody></table><p>The options are:</p><table tabindex="0"><thead><tr><th>Options</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><code>transport</code></td><td>the transport layer used by the <strong>Feathers</strong> client application. For now it is required.</td><td></td></tr><tr><td><code>servicePath</code></td><td>the path to the service.</td><td><code>s3</code></td></tr><tr><td><code>chunkSize</code></td><td>the size of the chunk to perfom multipart upload.</td><td><code>5MB</code></td></tr><tr><td><code>useProxy</code></td><td>define whether to use backend as a proxy for custom methods.</td><td><code>false</code></td></tr><tr><td><code>fetch</code></td><td>the fetch function.</td><td>browser fetch function</td></tr><tr><td><code>btoa</code></td><td>the binary to ascii function used to transform sent data into a string.</td><td>transform to base64</td></tr><tr><td><code>atob</code></td><td>the ascii to binary function used to transform received data into a Buffer.</td><td>transform from base64</td></tr><tr><td><code>debug</code></td><td>the debug function.</td><td>null</td></tr></tbody></table><h2 id="upload-id-blob-options" tabindex="-1">upload (id, blob, options) <a class="header-anchor" href="#upload-id-blob-options" aria-label="Permalink to &quot;upload (id, blob, options)&quot;">​</a></h2><p>Upload a <strong>Blob</strong> object to the bucket with the given key <code>id</code>.</p><p>According the size of chunk you set when instanciang the client service and the size of the <code>blob</code>, the method will automatically perform a <code>singlepart</code> upload or a <code>mulitpart</code> upload.</p><p>If the <code>proxy</code> option is undefined. The client performs the upload action directly using <strong>fetch</strong>. Otherwise, it uses the <a href="#proxyupload">proxyUpload</a> custom method.</p><table tabindex="0"><thead><tr><th>Argument</th><th>Description</th><th>Required</th></tr></thead><tbody><tr><td><code>id</code></td><td>the object key. Note that the final computed <strong>Key</strong> takes into account the <code>prefix</code> option of the service.</td><td>yes</td></tr><tr><td><code>blob</code></td><td>the content of the object to be uploaded defined as a <strong>Blob</strong>.</td><td>yes</td></tr><tr><td><code>options</code></td><td>options to be forwarded to the underlying service methods.</td><td>no</td></tr></tbody></table><h2 id="download-key-type-options" tabindex="-1">download (key, type, options) <a class="header-anchor" href="#download-key-type-options" aria-label="Permalink to &quot;download (key, type, options)&quot;">​</a></h2><p>Download an object from the bucket with the given key <code>id</code>.</p><p>If the <code>proxy</code> option is undefined. The client performs the download action directly using <strong>fetch</strong>. Otherwise, it uses the <a href="#getObject">getObject</a> custom method.</p><table tabindex="0"><thead><tr><th>Argument</th><th>Description</th><th>Required</th></tr></thead><tbody><tr><td><code>id</code></td><td>the object key. Note that the final computed <strong>Key</strong> takes into account the <code>prefix</code> option of the service.</td><td>yes</td></tr><tr><td><code>type</code></td><td>the type of the content to be downloaded.</td><td>yes</td></tr><tr><td><code>options</code></td><td>options to be forwarded to the underlying service methods.</td><td>no</td></tr></tbody></table>',15)])])}const f=e(a,[["render",n]]);export{u as __pageData,f as default};
